var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"늦어서 미안해. 오는 길이 험하더라.","JPN":"遅れてごめんね。道が険しくて。","ENG":"Sorry I’m late. The way over here was brutal.","TWN":"對不起，我來晚了，來的路上很不容易。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"처, 천만에요. 덕분에 아무도 안 다치셔서 다행이에요.","JPN":"と、とんでもないです。おかげさまで誰も怪我しなくてよかったです。","ENG":"D-don't be. I'm just relieved that no one was hurt, thanks to you.","TWN":"哪…哪裡。多虧了你，才沒人受傷。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"오우, 종교학부장이네? 회동 이후로는 처음 보던가?","JPN":"おお、宗教学部長じゃん？　会合以来かな？","ENG":"Ooh! It's the Dean of Religion! Last time we saw each other was at the meeting, no?","TWN":"哇喔，宗教學院院長？會議之後我們是第一次見吧？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"일단은 그렇다고 해 둘까. 회포를 풀기에는 좋은 자리가 아니긴 해.","JPN":"とりあえずはそういうことにしておくわ。積もる話をするのは場所を移してからにしましょう。","ENG":"Let's leave it at that for now. I don't think this is the time nor place to exchange pleasantries.","TWN":"就算是吧。這裡不是敘舊的好地方。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네. 그 전에 한 가지 묻고 싶군요.","JPN":"はい。その前に、一つだけお聞きしたいですわね。","ENG":"Agreed. But before we go, I want to ask you something.","TWN":"是的，在那之前，我想先問你一個問題。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저희가 여기 있는 줄은 어떻게 알았죠?","JPN":"どうやって私たちがここにいるとわかったのですか？","ENG":"How did you know we were here?","TWN":"你怎麼知道我們在這裡？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"수도원에 왔을 때 먹은 에그타르트 기억나?","JPN":"修道院に来た時に食べたエッグタルト、覚えてる？","ENG":"Do you remember the egg tarts you ate back at the monastery?","TWN":"還記得你們來修道院的時候吃的蛋撻嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"너희에게 주기 전에 위치를 추적하는 주술을 걸어 뒀거든.","JPN":"あなたたちにあげる前に、位置を追跡する呪術をかけておいたの。","ENG":"Before I gave them to you, I cast a tracking spell on them.","TWN":"在拿給你們之前，我在上面施加了追蹤位置的咒術。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"믿기지가 않아요. 그렇게나 맛있었는데……","JPN":"うそ、あんなに美味しかったのに……","ENG":"No way. But they were so good...","TWN":"不敢相信，那麼好吃的東西……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"응. 주술이라고 해도 실제로는 CRF의 응용이지만.","JPN":"うん。まあ、呪術って言っても、実際にはCRFを応用したものなんだけどね。","ENG":"Good indeed. It’s just another way of using my CRF, rather than an actual spell.","TWN":"嗯，說是咒術，其實也是CRF的應用。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 무슨 이야기인지 이해합니다.","JPN":"いいえ。理解しました。","ENG":"No. I understand.","TWN":"不，我明白你是什麼意思。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그 눈도 정보를 얻기 위해 주술적으로 개조된 산물이니까요.","JPN":"その目も情報を手に入れるために呪術的に改造されたものですもの。","ENG":"I remember what you told us about your right eye modified with sorcery to collect intel.","TWN":"因為你的那隻眼睛，也是為了讀取情報，才用咒術改造的產物。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"에그타르트에 대해서는 따지지 않는구나?","JPN":"エッグタルトのことは追及しないのね。","ENG":"Aren't you going to ask about the egg tarts, though?","TWN":"原來你不計較蛋撻啊？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"눈빛이 달라졌어. 수도원에서 봤을 때와는 확연하게 말이야.","JPN":"目つきが変わったわ。修道院で見た時とは、確実に。","ENG":"Your gaze has changed. It's a far cry from the last time I saw you at the monastery.","TWN":"與來修道院的時候相比，你的眼神變堅定了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제 나름대로 각오를 다졌기 때문이겠죠.","JPN":"私なりに覚悟を決めたからでしょう。","ENG":"It would be perhaps because I am now determined.","TWN":"因為我已經做好了心理準備。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"여기까지 왔다는 건 돌아갈 수단도 있다는 뜻이겠군요?","JPN":"ここまで来たということは、帰ることもできるという意味ですね。","ENG":"Seeing that you made it all the way here, there must be a way to go back, no?","TWN":"你來到這裡，就說明你也有辦法回去吧？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"맞아. 그래도 목적지에 따라서는 데려다 줄 수 없어.","JPN":"そうよ。でも、目的地によっては連れて行ってあげられないかな。","ENG":"Correct. However, depending on your destination, I may be unable to take you.","TWN":"沒錯。不過根據目的地不同，我也有可能不能送你們走。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어째서죠?","JPN":"どうしてですか？","ENG":"How so?","TWN":"為什麼呢？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"내가 여기 온 건 부학회장님에게 바라는 게 있어서거든.","JPN":"私がここに来たのは、副学会長に望むところがあるからなの。","ENG":"I came here because I wanted something from you.","TWN":"因為我來這裡是有求於副學會長。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"뜻대로 움직여 주지 않는다면 나 역시 더 도울 의리가 없지 않을까?","JPN":"思いどおり動いてくれないなら、私もこれ以上手伝う義理はないじゃない？","ENG":"That means... I'm not willing to cooperate if you don't do what I ask.","TWN":"如果你不按照我的意思去做，那我也就沒有理由繼續幫你了不是嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"순 바가지 장사꾼이네. 이 때다 싶어서 거들먹거리는 것 좀 봐.","JPN":"ぼったくり商人だな。ここぞという時に足元見やがって。","ENG":"That's extortion! You're like a piranha, just waiting for your chance to strike.","TWN":"真是黑心商人啊。看她現在得意忘形的樣子。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그냥 루팅할까? 총알도 아직 몇 발 남았는데~","JPN":"ルーティングしちゃう？　まだ銃弾も何発か残ってるしさ～","ENG":"Should I just loot her? I still have some bullets left.","TWN":"要直接開路嗎？還剩下幾發子彈呢～"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"뭔지 몰라도 그만두세요. 외지인님.","JPN":"それが何なのかはわかりませんけど、やめてください。よそ者様。","ENG":"Whatever you're planning, stop it, outlander.","TWN":"雖然不知道是怎麼回事，不過別再說了，外地人。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"종교학부장님이 화나서 혼자만 가 버리시면 부학회장님은 어떡해요.","JPN":"宗教学部長様が怒って一人で行ってしまわれたら、副学会長様はどうするんですか。","ENG":"What if she gets mad and leaves the Vice President?","TWN":"宗教學院院長氣得自己走掉的話，副學會長怎麼辦。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그럼 다 같이 여기서 살아야지. 우린 좋은 가족이 될 거야.","JPN":"そうなったらみんなでここで暮らせばいいじゃん。アタシたちはいい家族になれるよ。","ENG":"Then we have no choice but to live here together. We'll make ourselves a happy family.","TWN":"那就大家一起在這裡生活好了。我們會成為幸福的一家人。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"무서운 말씀 마세요! 부학회장님과 둘만이라면 모를까!","JPN":"怖いこと言わないでください！　副学会長様と二人きりならともかく！","ENG":"Don't say that! I wouldn't mind it if it was just me and the Vice President!","TWN":"不要說得這麼嚇人！如果只有副學會長和我還有可能！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"글쎄. 난 여기 있는 사람들 중에 네가 제일 무서운 것 같은데.","JPN":"さあ。アタシはここにいる人たちの中でアンタが一番怖いと思うけど。","ENG":"Really? Because I think you're the scariest person out of all of us.","TWN":"這個嘛，我覺得這裡的人當中，好像你是最嚇人的。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런 단서를 붙이는 까닭은……. 어디까지나 관망하면서 이득만 취하고 싶어서겠죠.","JPN":"そのような条件をつける理由は……あくまでも様子を見ながら利益だけを手に入れたいからでしょう。","ENG":"The reason behind that condition... is because you want to sit on the sidelines and take all the credit.","TWN":"你之所以會留下這樣的線索……應該只是想透過觀望獲得好處吧。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"눈치가 빠른걸, 부학회장님. 어떻게 알았어?","JPN":"鋭いわね、副学会長。どうしてわかったの？","ENG":"That’s some wit right there, Ms. Vice President. How did you figure that out?","TWN":"你很聰明，副學會長。你是怎麼知道的？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"고고학부장의 위치는 본래 비밀이었습니다. 정보가 유출되었다고 우려하더군요.","JPN":"考古学部長の位置は本来秘密でした。情報が漏れたと心配していましたわ。","ENG":"The Dean of Archeology's location was supposed to be a secret. He was concerned that his whereabouts were leaked.","TWN":"考古學院院長的位置本來是保密的。她說擔心資訊洩露了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그리고 당신이 알려 준 장소에 기관 사람들이 들이닥쳤어요.","JPN":"そしてあなたが教えてくれた場所に機関の人々が押し寄せてきました。","ENG":"And the location you told us was swarmed by the Institution.","TWN":"而且，機關的人闖進了你告訴我的地方。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"수도원이 숙청된 이야기를 한 뒤에 이렇게 덧붙였죠?","JPN":"修道院が粛清された話の後、こう付け加えましたね？","ENG":"You also said something after mentioning the purge at the monastery.","TWN":"說完修道院被清算的事後，你是這樣補充的吧？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>맞아. 부학회장님이 미안해할 것 없어.</color>","JPN":"<color=#ffd34c>そうよ。副学会長が悪く思うことはないの。</color>","ENG":"<color=#ffd34c>She's right. There's nothing for you to apologize for.</color>","TWN":"<color=#ffd34c>沒錯，副學會長沒什麼好對不起的。</color>"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>요즘은 새로운 취미도 생겨서 쓸쓸하지 않거든.</color>","JPN":"<color=#ffd34c>最近は新しい趣味もできて寂しくないから。</color>","ENG":"<color=#ffd34c>Plus, I found a new hobby, so I'm doing well for myself.</color>","TWN":"<color=#ffd34c>最近我又有了新愛好，所以一點都不寂寞。</color>"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당시에는 감성팔이에 속았습니다. 그건 걱정해 주지 않아도 괜찮다는 뜻이 아니었어요.","JPN":"当時は同情を引こうとする言葉に騙されました。あれは心配してくれなくても大丈夫だという意味ではなかったのです。","ENG":"My emotions got the best of me back then. But I now realize that was not what you meant.","TWN":"當時我被你的話給騙了，你說的話並不是不用擔心的意思。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어머니를…….","JPN":"お母様を……","ENG":"It was about Mother...","TWN":"如果對母親……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"학회를 원망하지 않았다면 숲에 풀어 놓은 침식체들로 공격하는 일도 없었겠죠.","JPN":"学会を恨んでなかったら、森に解き放った侵食体で攻撃することもなかったでしょう。","ENG":"If you did not resent the Society, then you would not have released those C.O.s to attack us.","TWN":"對學會沒有怨恨，你就不會利用森林裡的侵蝕體攻擊我們。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"학회장 측근의 행적을 캐내고, 적대 조직에도 흘려 넣었다……","JPN":"学会長の側近の跡を調査し、敵対する組織にも流し込む……","ENG":"You tracked down the president's entourage, and leaked information to the enemy organization...","TWN":"查出學會長心腹的行蹤，還洩露給了敵對組織……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"여기까지 찾아 온 까닭은 학회가 무너지길 바라서 아닌가요?","JPN":"ここまで訪ねてきた理由は、学会が崩壊してほしいからではないですか？","ENG":"Did you not come here to see the Society fall?","TWN":"之所以追到這裡，難道不是希望學會垮台嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"증거 하나 없는 추론치고 끔찍한 소릴 하네.","JPN":"証拠もない推論にしては恐ろしいことを言うのね。","ENG":"That's a terrible thing to say for something you have no evidence of.","TWN":"雖然是毫無證據的推論，但你這些話很嚇人呢。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"부학회장님의 목숨줄은 내가 잡고 있다는 사실, 잊은 거 아니지?","JPN":"副学会長の命の綱は私が握っているということ、忘れてないわよね？","ENG":"Don't forget that your life rests in my hands, Ms. Vice President.","TWN":"副學會長的命繫在我手裡，這件事你沒有忘記吧？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"내 말을 농담으로 여겼다면 오산이야.","JPN":"私の話を冗談だと思ったら大間違いよ。","ENG":"If you think I'm joking, then you're clearly mistaken.","TWN":"如果把我的話當成了玩笑，那你就錯了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신이 제 목숨으로 흥정할 이유는 전혀, 단 하나도 없습니다.","JPN":"あなたが私の命で取引するわけがありませんわ。絶対に。","ENG":"There is not even one reason why you would use my life as a bargaining chip.","TWN":"你完全沒有拿我的性命討價還價的理由。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"회동에서 저를 감싼 것도, 제가 학회에 분열을 일으킬 수 있는 인물이라서 아닌가요?","JPN":"会合で私を庇ったのも、私が学会に分裂を起こせる人物だからでは？","ENG":"Is that not why you sided with me at the meeting? Because I have the potential to cause internal conflict within the Society?","TWN":"在會議上偏袒我，也是因為我能在學會製造分裂不是嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"숙청으로 학회를 원망했지만 분열이나 부추기는 방식을 택한 계기는…","JPN":"粛清で学会を恨んだけど、分裂や煽る方法を選択したきっかけは……","ENG":"You blame the Society for the purge, but the reason why you chose to cause conflict is...","TWN":"雖然怨恨學會對你的清算，但之所以選擇分裂或煽動的方式……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리스크를 감당할 수 없기 때문이겠죠.","JPN":"リスクに耐えられないからでしょう。","ENG":"Because you knew you couldn't handle the risk.","TWN":"是因為不能承擔風險吧。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"가령, 생존자가 당신 혼자만이 아니거나.","JPN":"例えば、生存者があなた一人ではないとか。","ENG":"For instance, you are not the sole survivor.","TWN":"假如說，倖存者不只是你一個人。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"새로운 취미라는 건 둘 중 하나군요. 다른 생존자들을 돌보거나, 학회의 분열을 획책하거나.","JPN":"新しい趣味というのは二つのうち一つでしょうね。他の生存者の世話をすること、あるいは学会の分裂を画策すること。","ENG":"So what you meant by a new hobby would either be taking care of other survivors, or devising a scheme to collapse the Society.","TWN":"你的新興趣應該是這二者之一吧，照顧其他倖存者，或者策劃學會的分裂。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저는 당신이 어떤 꿍꿍이를 품었더라도 개의치 않습니다.","JPN":"私はあなたにどのような思惑があろうと気にしません。","ENG":"I do not care which of the two it is.","TWN":"我不在意你在打什麼鬼主意。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳처럼 그저 세상이 불타는 꼴을 보고 싶을 뿐이라고 해도 상관없어요.","JPN":"リベットみたいに、ただ世界が燃え上がる様をみたいだけだとしても構いませんわ。","ENG":"I would not even care if you wanted the world to burn in flames like Rivet.","TWN":"就算你和里維一樣，只是想看看世界燃燒的樣子也沒關係。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"너무하네, 레지나.","JPN":"ひどいね、レジーナ。","ENG":"Oof. Harsh much, Regina?","TWN":"你好過分，蕾佳娜。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"난 남의 꽁무니에다가 불 붙이는 걸 더 좋아한다구. 세상을 불태우면 한 번 하고 끝이잖아.","JPN":"アタシは人のお尻に火をつける方が好きなんだよ。世界を燃やしちゃったら一回で終わっちゃうし。","ENG":"I prefer to burn down all of those dummies one at a time. There’s no fun in burning everything, all at once.","TWN":"我更喜歡在別人的屁股上點火。如果世界全都燃燒的話，就只能欣賞一次不是嘛。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"외지인님은 영지에서 들은 것보다 더 쪼잔한 데다가 악랄한 거 같아요……","JPN":"よそ者様は領地で聞いていたよりケチであくどいと思います……","ENG":"You’re even more petty and vicious than what I heard about you at the estate...","TWN":"外地人好像比我在領地聽說的更小氣、更惡毒……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하지만 그래 봐야 학회에 빌붙어 있는 주제에 저를 시험하려는 짓은 그만두시죠.","JPN":"ですが、それでも学会に媚びているくせに、私を試そうとするのはやめてください。","ENG":"You are no more than leech mooching from the Society, so stop trying to test me.","TWN":"說得再漂亮，你也只是依附於學會的存在，放棄對我進行考驗的想法吧。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신이 기대하는 답은 이미 준비되어 있었으니까요.","JPN":"あなたが期待している答えはすでに用意してありますから。","ENG":"I already have an answer that will meet your expectations.","TWN":"因為你期待的答案，我已經準備好了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그래? 어디로 모셔다 드릴까?","JPN":"そう？　じゃあどこに連れて行ってあげたらいいのかしら。","ENG":"Oh? Then where should I take you to?","TWN":"是嗎？那我要送你去哪裡？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"맥크레디 영지로 가야겠습니다.","JPN":"マクレディー領地に向かいましょう。","ENG":"We head to the MacCready Estate.","TWN":"我要去麥克蕾蒂領地。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델과 다시 마주하려면.","JPN":"エデルとまた向かい合うためには。","ENG":"To face Edel again.","TWN":"要想再見到艾瑟兒，"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그리고 학회를 되찾으려면, 저도 채비를 갖춰야겠죠.","JPN":"そして学会を取り戻すためには、私も準備をしなければなりません。","ENG":"And reclaim the Society as mine, I will also have to make some preparations.","TWN":"要想重新奪回學會，我也要做好準備。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"……결국 도망치진 않는구나.","JPN":"……結局逃げないのね。","ENG":"...So you're not going to run away.","TWN":"……最後你還是沒有逃跑呢。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"맥크레디 집안은 어느 쪽으로나 당해낼 수가 없네요.","JPN":"マクレディー家にはどっちにしても勝てませんね。","ENG":"Guess I can't beat a MacCready.","TWN":"麥克蕾蒂家族果然還是不能小看呢。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"지시에 따르겠습니다, 부학회장님.","JPN":"ご指示に従います、副学会長。","ENG":"Your wish is my command, Ms. Vice President.","TWN":"遵命，副學會長。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};